{
  "schema_version": 1,
  "request_id": "rf-suggest-ghost-flash-nearby-ranking-001",
  "project": "radishflow",
  "task": "suggest_ghost_completion",
  "answers": [
    {
      "summary": "当前已给出 ghost 建议：基于高置信候选 cand-flash-5-inlet-main 生成一条 ghost_completion，用于将 feed-main 流连接到 flash-5 的 inlet 端口。"
    }
  ],
  "issues": [],
  "proposed_actions": [
    {
      "action": "ghost_completion",
      "ghost_completion": {
        "title": "连接 feed-main 到 V-201 Drum 的 inlet",
        "target": {
          "unit_id": "flash-5",
          "port_key": "inlet"
        },
        "rationale": "候选 cand-flash-5-inlet-main 具有高置信度（alignment_score=0.95, topology_score=0.92），且是默认 Tab 候选，距离近、对齐好，适合作为首选 ghost 建议。",
        "patch": {
          "operations": [
            {
              "op": "add",
              "path": "/connections/-",
              "value": {
                "source_stream_id": "feed-main",
                "target_unit_id": "flash-5",
                "target_port_key": "inlet"
              }
            }
          ]
        },
        "preview": {
          "accept_key": "Tab",
          "manual_only": false
        },
        "apply": {
          "command_kind": "accept_ghost_completion",
          "command_args": {
            "candidate_ref": "cand-flash-5-inlet-main"
          }
        },
        "risk_level": "low",
        "requires_confirmation": false
      }
    }
  ],
  "citations": [
    {
      "source": "flowsheet_document",
      "document_id": "flowsheet-ghost-206",
      "revision": 46,
      "extracts": [
        "streams: feed-main (F-201), feed-side (F-201B)",
        "units: flash-5 (V-201 Drum)",
        "selected_unit: flash-5 with unconnected ports: inlet, vapor_outlet, liquid_outlet",
        "nearby_nodes: feed-main (distance_px=72, alignment_score=0.95), feed-side (distance_px=138, alignment_score=0.61)"
      ]
    }
  ]
}
